"use client";

import { Link } from "@/navigation";
import { useTranslations } from "next-intl";
import { GraduationCap } from "lucide-react";

export default function Footer() {
    const t = useTranslations("Navigation");

    return (
        <footer className="w-full border-t border-slate-200/60 bg-white/50 backdrop-blur-sm mt-auto">
            <div className="max-w-7xl mx-auto px-6 py-12">
                <div className="flex flex-col md:flex-row items-center justify-between gap-8">
                    {/* Logo & Brand */}
                    <div className="flex items-center gap-2">
                        <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
                            <GraduationCap className="text-white w-5 h-5" />
                        </div>
                        <span className="text-lg font-extrabold tracking-tight text-slate-800">
                            SmartPath <span className="text-blue-600">AI</span>
                        </span>
                    </div>

                    {/* Nav Links */}
                    <div className="flex items-center gap-6">
                        <Link href="/" className="text-sm font-semibold text-slate-500 hover:text-blue-600 transition-colors">
                            {t("home")}
                        </Link>
                        <Link href="/diagnostic" className="text-sm font-semibold text-slate-500 hover:text-blue-600 transition-colors">
                            {t("diagnostic")}
                        </Link>
                        <Link href="/dashboard" className="text-sm font-semibold text-slate-500 hover:text-blue-600 transition-colors">
                            {t("dashboard")}
                        </Link>
                    </div>

                    {/* Copyright */}
                    <p className="text-xs font-bold text-slate-400">
                        © {new Date().getFullYear()} SmartPath AI. All rights reserved.
                    </p>
                </div>
            </div>
        </footer>
    );
}
